    TResult Function(InTimeChanged value)? inTimeChanged,
    TResult Function(OutTimeChanged value)? outTimeChanged,
    TResult Function(RouteToHRChanged value)? routeToHRChanged,
    TResult Function(ReasonChanged value)? reasonChanged,
    TResult Function(UploadFileRequested value)? uploadFileRequested,
    TResult Function(FileRemoved value)? fileRemoved,
    TResult Function(SubmitRequested value)? submitRequested,
    TResult Function(ResetRequested value)? resetRequested,
    required TResult orElse(),
  }) {
    if (resetRequested != null) {
      return resetRequested(this);
    }
    return orElse();
  }
}

abstract class ResetRequested implements AttendanceRegularizationEvent {
  const factory ResetRequested() = _$ResetRequestedImpl;
}
